    "http://localhost/api/v1/actores" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: multipart/form-data" \
    --header "Accept: application/json" \
    --form "identificador_institucional=b"\
    --form "nombre=n"\
    --form "tipo=Academia"\
    --form "pais_origen=g"\
    --form "estado=Inactivo"\
    --form "contacto_nombre=z"\
    --form "contacto_email=rempel.chadrick@example.org"\
    --form "contacto_telefono=l"\
    --form "sitio_web=j"\
    --form "notas=architecto"\
    --form "areas_tematicas[]=n"\
    --form "logo=@C:\Users\User\AppData\Local\Temp\php6B1A.tmp" </code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/v1/actores"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "multipart/form-data",
    "Accept": "application/json",
};

const body = new FormData();
body.append('identificador_institucional', 'b');
body.append('nombre', 'n');
body.append('tipo', 'Academia');
body.append('pais_origen', 'g');
body.append('estado', 'Inactivo');
body.append('contacto_nombre', 'z');
body.append('contacto_email', 'rempel.chadrick@example.org');
body.append('contacto_telefono', 'l');
body.append('sitio_web', 'j');
body.append('notas', 'architecto');
body.append('areas_tematicas[]', 'n');
body.append('logo', document.querySelector('input[name="logo"]').files[0]);

fetch(url, {
    method: "POST",
    headers,
    body,
}).then(response =&gt; response.json());</code></pre></div>

